#[test]
fn test_process_enforces_token_budget() {
    let config = ChunkingConfig {
        max_tokens: 10, // ~40 chars
        min_tokens: 2,
        overlap_tokens: 0,
        strategy: "auto".into(),
    };
    let pipeline = make_pipeline(config);
    let source = "a]".repeat(200); // 400 chars = 100 tokens, way over budget
    let chunks = pipeline.process(&source, &test_meta("txt")).unwrap();
    for chunk in &chunks {
        assert!(
            chunk.token_estimate <= 20, // some tolerance for split boundaries
            "chunk has {} tokens, exceeds budget of 10",
            chunk.token_estimate
        );
    }
}

#[test]
fn test_process_merges_small_chunks() {
    let config = ChunkingConfig {
        max_tokens: 512,
        min_tokens: 50, // 200 chars minimum
        overlap_tokens: 0,
        strategy: "auto".into(),
    };
    let pipeline = make_pipeline(config);
    // Paragraphs that are individually small (< min_tokens)
    let source = "Short paragraph.\n\nAnother short one.\n\nThird short paragraph.";
    let chunks = pipeline.process(source, &test_meta("txt")).unwrap();
    // Should merge into fewer chunks since each paragraph is small
    assert!(
        chunks.len() <= 2,
        "expected merging to reduce chunk count, got {}",
        chunks.len()
    );
}

